/**
 * Kotlin/JVM's `String.toInt()`/`toIntOrNull()` is Unicode-aware (via `Character.digit`) and accepts e.g. Arabic-Indic
 * and full-width digits. The datetime parsing API is intentionally ASCII-only.
 */
private fun String.toAsciiIntOrNull(maxDigits: Int? = null): Int? {
    if (isEmpty()) return null
    if (maxDigits != null && length > maxDigits) return null
    var result = 0
    for (ch in this) {
        val digit = ch.code - '0'.code
        if (digit !in 0..9) return null
        if (result > (Int.MAX_VALUE - digit) / 10) return null
        result = result * 10 + digit
    }
    return result
}
"}

